sys_script_client.script:
function onSubmit() {
	var formAction = g_form.getActionName();
	if(formAction == 'Save & Assign Task'){
		if(g_scratchpad.suspenseDatesAndExpctedStartDatesMustBeInTheFuture == 'true'){
			if(g_form.getValue('suspense_date')){
				var suspense_date_number = new Date(g_form.getValue('suspense_date')).getTime();
				var now = new Date().getTime();
				if(suspense_date_number < now){
					g_form.addErrorMessage(getMessage('The suspense date must be in the future.'));
					return false;
				}
			}
		}	   
	}
}
